import React from 'react'
import { Button, DialogOverlay, DialogOverlayActions, DialogOverlayFooter, Paragraph } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'

export default function MarkPersonDeceasedFgtDialog({ overlay, treeId, loading }): JSX.Element {
  const [t] = useTranslation()

  return (
    <DialogOverlay {...overlay} title={t('conclusion.mark-deceased.heading')}>
      <Paragraph size="sm">{t('conclusion.fgt-mark-deceased.description')}</Paragraph>

      <DialogOverlayFooter>
        <DialogOverlayActions>
          <Button data-testid="fgt-person-deceased:cancel-action" onClick={overlay.close}>
            {t('common-ui:cancel.action')}
          </Button>
          <Button
            emphasis="high"
            disabled={loading}
            external
            data-testid="mark-deceased-manage-members:button"
            to={`/groups/switch/${treeId}?openGroupMembers=true`}
          >
            {t('conclusion.manage-members.action')}
          </Button>
        </DialogOverlayActions>
      </DialogOverlayFooter>
    </DialogOverlay>
  )
}
